lcd = OledBoot()
# Initialize screen
lcd.fill(0)
lcd.show()

def idle_fw( lcd, x, y ):
    global all_icons
    for icon in all_icons:
        lcd.fill(0) # Clear
        # Draw first image
        draw_icon( lcd, icon,x,y,1 )
        lcd.show()
        #time.sleep_ms( 150 )

while True:
	x,y = 35, 15
	idle_fw( lcd, x, y )
		
